export function renderCompactFace(speciesId, eyeChar) {
    switch (speciesId) {
        case "duck":
        case "goose":
            return `(${eyeChar}>`;
        case "blob":
            return `(${eyeChar}${eyeChar})`;
        case "cat":
            return `=${eyeChar}ω${eyeChar}=`;
        case "maltese":
            return `(${eyeChar}w${eyeChar})~`;
        case "dragon":
            return `<${eyeChar}~${eyeChar}>`;
        case "octopus":
            return `~(${eyeChar}${eyeChar})~`;
        case "owl":
            return `(${eyeChar})(${eyeChar})`;
        case "penguin":
            return `(${eyeChar}>)`;
        case "turtle":
            return `[${eyeChar}_${eyeChar}]`;
        case "snail":
            return `${eyeChar}(@)`;
        case "ghost":
            return `/${eyeChar}${eyeChar}\\`;
        case "axolotl":
            return `}${eyeChar}.${eyeChar}{`;
        case "capybara":
            return `(${eyeChar}oo${eyeChar})`;
        case "cactus":
        case "mushroom":
            return `|${eyeChar}  ${eyeChar}|`;
        case "robot":
            return `[${eyeChar}${eyeChar}]`;
        case "rabbit":
            return `(${eyeChar}..${eyeChar})`;
        case "chonk":
            return `(${eyeChar}.${eyeChar})`;
        case "tanuki":
            return `(${eyeChar}w${eyeChar})`;
        case "fox":
            return `<${eyeChar}v${eyeChar}>`;
        case "frog":
            return `(${eyeChar}__${eyeChar})`;
        case "crystal":
            return `<${eyeChar}${eyeChar}>`;
        case "jellyfish":
            return `(${eyeChar}${eyeChar})~`;
        default:
            return `(${eyeChar}w${eyeChar})`;
    }
}
